  ('project-tini', 'dark-side-of-the-tini', 'DARK SIDE OF THE TINI', 'Treating stone (Tini) as the soulful protagonist of design.', '/works/tini/cover.png', 'Product Design', '10.2025~11.2025', 'Deutschland', 'Po-Yu Yang and Nick Düchs', '["Grasshopper","Computational Design","Prototyping"]', 'published', 0, 3400, 420, '2025-11-01T00:00:00.000Z'),
  ('project-portfolio-2025', '2025-industrial-design-portfolio', '2025 INDUSTRIAL DESIGN PORTFOLIO', 'A comprehensive collection of my industrial design works and explorations.', '/works/portfolio/2025portfolio (1).jpg', 'Portfolio', '02.2025', 'Taiwan', 'Po-Yu Yang', '["Industrial Design","Portfolio"]', 'published', 1, 2100, 120, '2025-02-01T00:00:00.000Z'),
  ('project-explo-11', 'explo-11', 'Explo.11探索十一號', 'A comprehensive exploration of automotive design and digital portfolio presentation.', '/works/explo.11/cover.png', 'Product Design', '10.2024~04.2025', 'Taiwan', 'Po-Yu Yang, Chih-Huang Chou, Hsiao-Kuang Hsu', '["Industrial Design","3D Modeling","Visual Design"]', 'published', 2, 1800, 95, '2025-04-01T00:00:00.000Z'),
  ('project-tube-radio', 'tube-radio', 'Tube Radio', 'Design Styling Practice', '/works/tube/tube (1).jpg', 'Product Design', '11.2023', 'Taiwan', 'Po-Yu Yang', '["Industrial Design","3D Modeling"]', 'published', 3, 850, 34, '2023-11-01T00:00:00.000Z'),
  ('project-invisible-senses', 'invisible-senses', 'Invisible Senses', 'Exploring the subtle and often overlooked sensory experiences in our daily lives.', '/works/invisible/invisible (1).jpg', 'Product Design', '09.2023~12.2023', 'Taiwan', 'Po-Yu Yang', '["Industrial Design","User Research"]', 'published', 4, 1200, 56, '2023-12-01T00:00:00.000Z');

INSERT OR IGNORE INTO project_blocks (id, project_id, block_type, content_json, sort_order) VALUES
  ('block-tini-main', 'project-tini', 'gallery', '{"images":[{"url":"/works/tini/tini main (1).png"},{"url":"/works/tini/tini main (2).png"}],"columns":1,"gap":"none"}', 0),
  ('block-tini-details', 'project-tini', 'gallery', '{"images":[{"url":"/works/tini/tini small pics (1).png"},{"url":"/works/tini/tini small pics (2).png"},{"url":"/works/tini/tini small pics (3).png"},{"url":"/works/tini/tini small pics (4).png"},{"url":"/works/tini/tini small pics (5).png"},{"url":"/works/tini/tini small pics (6).png"}],"columns":3,"gap":"none","square":true}', 1),
  ('block-tini-process', 'project-tini', 'gallery', '{"images":[{"url":"/works/tini/tini (1).jpg"},{"url":"/works/tini/tini (2).jpg"},{"url":"/works/tini/tini (3).jpg"},{"url":"/works/tini/tini (4).jpg"},{"url":"/works/tini/tini (5).jpg"},{"url":"/works/tini/tini (6).jpg"},{"url":"/works/tini/tini (7).jpg"},{"url":"/works/tini/tini (8).jpg"},{"url":"/works/tini/tini (9).jpg"},{"url":"/works/tini/tini (10).jpg"},{"url":"/works/tini/tini (11).jpg"},{"url":"/works/tini/tini (12).jpg"},{"url":"/works/tini/tini (13).jpg"},{"url":"/works/tini/tini (14).jpg"},{"url":"/works/tini/tini (15).jpg"},{"url":"/works/tini/tini (16).jpg"},{"url":"/works/tini/tini (17).jpg"},{"url":"/works/tini/tini (18).jpg"},{"url":"/works/tini/tini (19).jpg"}],"columns":1,"gap":"none"}', 2),
  ('block-tini-text', 'project-tini', 'text', '{"body":"DARK SIDE OF THE TINI, a collaborative project by Po-Yu Yang and Nick Düchs, centers on the vision of treating stone (Tini) as the soulful protagonist of design. Drawing inspiration from the Hizz rocking chair by Mentalla Said and Jumana Taha, the project emphasizes architectural geometry and material honesty. By simplifying all visual elements, the designers evoke an imagery of stones floating in space and emitting a celestial glow. Utilizing Grasshopper, the designers precisely calculated the centroid of each stone and generated support nodes based on their unique silhouettes. Through iterative prototyping, they resolved stability issues and developed a dual-layer base that echoes the stone texture while balancing the structure."}', 3),

