  ('block-portfolio-text', 'project-portfolio-2025', 'text', '{"body":"This portfolio showcases a curated selection of my industrial design projects, highlighting my journey, skills, and design philosophy."}', 1),

  ('block-explo-gallery', 'project-explo-11', 'gallery', '{"images":[{"url":"/works/explo.11/car portfolio (1).jpg"},{"url":"/works/explo.11/car portfolio (2).jpg"},{"url":"/works/explo.11/car portfolio (3).jpg"},{"url":"/works/explo.11/car portfolio (4).jpg"},{"url":"/works/explo.11/car portfolio (5).jpg"},{"url":"/works/explo.11/car portfolio (6).jpg"},{"url":"/works/explo.11/car portfolio (7).jpg"},{"url":"/works/explo.11/car portfolio (8).jpg"},{"url":"/works/explo.11/car portfolio (9).jpg"},{"url":"/works/explo.11/car portfolio (10).jpg"},{"url":"/works/explo.11/car portfolio (11).jpg"},{"url":"/works/explo.11/car portfolio (12).jpg"},{"url":"/works/explo.11/car portfolio (13).jpg"},{"url":"/works/explo.11/car portfolio (14).jpg"},{"url":"/works/explo.11/car portfolio (15).jpg"}],"columns":1,"gap":"none"}', 0),
  ('block-explo-text', 'project-explo-11', 'text', '{"body":"Explo.11 is a deep dive into automotive aesthetics and the art of digital storytelling. This project showcases a series of car design studies, focusing on fluid forms, aerodynamic efficiency, and the integration of advanced materials."}', 1),

  ('block-tube-gallery', 'project-tube-radio', 'gallery', '{"images":[{"url":"/works/tube/tube (1).jpg"},{"url":"/works/tube/tube (2).jpg"},{"url":"/works/tube/tube (3).jpg"},{"url":"/works/tube/tube (4).jpg"},{"url":"/works/tube/tube (5).jpg"},{"url":"/works/tube/tube (6).jpg"}],"columns":1,"gap":"none"}', 0),
  ('block-tube-text', 'project-tube-radio', 'text', '{"body":"TUBE is a design project that reimagines the classic vacuum tube radio for a modern audience, blending vintage aesthetics with contemporary manufacturing techniques."}', 1),

  ('block-invisible-gallery', 'project-invisible-senses', 'gallery', '{"images":[{"url":"/works/invisible/invisible (1).jpg"},{"url":"/works/invisible/invisible (2).jpg"},{"url":"/works/invisible/invisible (3).jpg"},{"url":"/works/invisible/invisible (4).jpg"},{"url":"/works/invisible/invisible (5).jpg"},{"url":"/works/invisible/invisible (6).jpg"},{"url":"/works/invisible/invisible (7).jpg"},{"url":"/works/invisible/invisible (8).jpg"},{"url":"/works/invisible/invisible (9).jpg"},{"url":"/works/invisible/invisible (10).jpg"},{"url":"/works/invisible/invisible (11).jpg"}],"columns":1,"gap":"none"}', 0),
  ('block-invisible-text', 'project-invisible-senses', 'text', '{"body":"Invisible Senses is a project that delves into the intangible aspects of human perception. By focusing on the senses that are often ignored, it aims to create a more profound connection between the user and their environment."}', 1);

